import type { PrismaClient } from '../../generated/prisma/client.js';

export async function seedHypocrite(prisma: PrismaClient, catMap: Record<string, string>) {
  await prisma.quiz.upsert({
    where: { slug: 'hypocrite' },
    update: {
      title: { es: '¿Qué tan hipócrita eres?', en: 'How much of a hypocrite are you?', fr: 'À quel point es-tu hypocrite ?', de: 'Wie heuchlerisch bist du?', it: 'Quanto sei ipocrita?', pt: 'O quanto você é hipócrita?' },
      description: { es: 'Todos predicamos algo que no siempre practicamos. ¿Qué tan grande es tu brecha?', en: 'We all preach things we don\'t always practice. How big is your gap?', fr: 'Nous prêchons tous des choses que nous ne pratiquons pas toujours. Quelle est la taille de ton écart ?', de: 'Wir alle predigen Dinge, die wir nicht immer praktizieren. Wie groß ist deine Lücke?', it: 'Tutti predichiamo qualcosa che non pratichiamo sempre. Quanto è grande il tuo divario?', pt: 'Todos pregamos algo que nem sempre praticamos. O quão grande é a sua lacuna?' },
      scenarioLabel: { es: 'Escenario', en: 'Scenario', fr: 'Scénario', de: 'Szenario', it: 'Scenario', pt: 'Cenário' },
      dimensionLabels: {
        es: { H: 'Hipocresía', C: 'Coherencia', A: 'Autoconciencia', F: 'Flexibilidad' },
        en: { H: 'Hypocrisy', C: 'Coherence', A: 'Self-awareness', F: 'Flexibility' },
        fr: { H: 'Hypocrisie', C: 'Cohérence', A: 'Conscience de soi', F: 'Flexibilité' },
        de: { H: 'Heuchelei', C: 'Kohärenz', A: 'Selbstbewusstsein', F: 'Flexibilität' },
        it: { H: 'Ipocrisia', C: 'Coerenza', A: 'Autoconsapevolezza', F: 'Flessibilità' },
        pt: { H: 'Hipocrisia', C: 'Coerência', A: 'Autoconhecimento', F: 'Flexibilidade' },
      },
      questions: [
        { id: 1, situation: { es: 'Criticas a la gente que llega tarde, pero tú llegas tarde regularmente.', en: 'You criticize people who are late, but you\'re late regularly yourself.', fr: 'Tu critiques les gens qui arrivent en retard, mais toi-même tu arrives régulièrement en retard.', de: 'Du kritisierst Menschen, die zu spät kommen, kommst aber selbst regelmäßig zu spät.', it: 'Critichi le persone che arrivano in ritardo, ma tu stesso/a arrivi regolarmente in ritardo.', pt: 'Você critica as pessoas que chegam atrasadas, mas você mesmo chega atrasado regularmente.' }, options: [{ text: { es: 'Sí, lo hago, pero en mi caso siempre hay razones válidas.', en: 'Yes, I do, but in my case there are always valid reasons.', fr: 'Oui, je le fais, mais dans mon cas il y a toujours des raisons valables.', de: 'Ja, das tue ich, aber in meinem Fall gibt es immer gültige Gründe.', it: 'Sì, lo faccio, ma nel mio caso ci sono sempre ragioni valide.', pt: 'Sim, faço isso, mas no meu caso sempre há razões válidas.' }, dimension: 'H' }, { text: { es: 'Si critico algo, trabajo para no hacerlo yo también.', en: 'If I criticize something, I work to not do it myself either.', fr: 'Si je critique quelque chose, je travaille à ne pas le faire moi-même non plus.', de: 'Wenn ich etwas kritisiere, arbeite ich daran, es selbst auch nicht zu tun.', it: 'Se critico qualcosa, lavoro per non farlo io stesso/a.', pt: 'Se critico algo, trabalho para não fazer o mesmo.' }, dimension: 'C' }, { text: { es: 'Lo reconozco: soy inconsistente en este tema.', en: 'I admit it: I\'m inconsistent on this.', fr: 'Je le reconnais : je suis incohérent(e) sur ce sujet.', de: 'Ich gebe es zu: Ich bin in dieser Hinsicht inkonsistent.', it: 'Lo riconosco: sono incoerente su questo tema.', pt: 'Reconheço: sou inconsistente nesse assunto.' }, dimension: 'A' }, { text: { es: 'Depende del contexto. La puntualidad no siempre tiene el mismo peso.', en: 'It depends on context. Punctuality doesn\'t always carry the same weight.', fr: 'Ça dépend du contexte. La ponctualité n\'a pas toujours le même poids.', de: 'Es hängt vom Kontext ab. Pünktlichkeit hat nicht immer das gleiche Gewicht.', it: 'Dipende dal contesto. La puntualità non ha sempre lo stesso peso.', pt: 'Depende do contexto. A pontualidade nem sempre tem o mesmo peso.' }, dimension: 'F' }] },
        { id: 2, situation: { es: 'Publicas contenido sobre salud mental mientras ignoras tus propias necesidades emocionales.', en: 'You post content about mental health while ignoring your own emotional needs.', fr: 'Tu publies du contenu sur la santé mentale tout en ignorant tes propres besoins émotionnels.', de: 'Du postest Inhalte über psychische Gesundheit, während du deine eigenen emotionalen Bedürfnisse ignorierst.', it: 'Pubblichi contenuti sulla salute mentale mentre ignori i tuoi stessi bisogni emotivi.', pt: 'Você posta conteúdo sobre saúde mental enquanto ignora suas próprias necessidades emocionais.' }, options: [{ text: { es: 'El contenido es útil para otros aunque yo no lo practique perfectamente.', en: 'The content is useful for others even if I don\'t practice it perfectly myself.', fr: 'Le contenu est utile pour les autres même si je ne le pratique pas parfaitement moi-même.', de: 'Der Inhalt ist für andere nützlich, auch wenn ich es nicht perfekt selbst praktiziere.', it: 'Il contenuto è utile per gli altri anche se io non lo pratico perfettamente.', pt: 'O conteúdo é útil para os outros mesmo que eu não o pratique perfeitamente.' }, dimension: 'H' }, { text: { es: 'Si lo publico, intento aplicarlo. Si no puedo, no lo publico.', en: 'If I post it, I try to apply it. If I can\'t, I don\'t post it.', fr: 'Si je le publie, j\'essaie de l\'appliquer. Si je ne peux pas, je ne le publie pas.', de: 'Wenn ich es poste, versuche ich es anzuwenden. Wenn ich das nicht kann, poste ich es nicht.', it: 'Se lo pubblico, cerco di applicarlo. Se non posso, non lo pubblico.', pt: 'Se publico, tento aplicar. Se não consigo, não publico.' }, dimension: 'C' }, { text: { es: 'Lo sé. Hay una brecha entre lo que digo y lo que hago.', en: 'I know. There\'s a gap between what I say and what I do.', fr: 'Je le sais. Il y a un écart entre ce que je dis et ce que je fais.', de: 'Ich weiß es. Es gibt eine Lücke zwischen dem, was ich sage, und dem, was ich tue.', it: 'Lo so. C\'è un divario tra quello che dico e quello che faccio.', pt: 'Eu sei. Há uma lacuna entre o que digo e o que faço.' }, dimension: 'A' }, { text: { es: 'Puedes saber la teoría y no aplicarla. No lo veo como hipocresía.', en: 'You can know the theory and not apply it. I don\'t see that as hypocrisy.', fr: 'On peut connaître la théorie sans l\'appliquer. Je ne vois pas ça comme de l\'hypocrisie.', de: 'Man kann die Theorie kennen und sie nicht anwenden. Ich sehe das nicht als Heuchelei.', it: 'Puoi conoscere la teoria senza applicarla. Non la vedo come ipocrisia.', pt: 'Você pode conhecer a teoria sem aplicá-la. Não vejo isso como hipocrisia.' }, dimension: 'F' }] },
        { id: 3, situation: { es: 'Exiges honestidad a los demás pero mientes cuando te conviene.', en: 'You demand honesty from others but lie when it suits you.', fr: 'Tu exiges l\'honnêteté des autres mais tu mens quand ça t\'arrange.', de: 'Du verlangst Ehrlichkeit von anderen, lügst aber, wenn es dir passt.', it: 'Esigi onestà dagli altri ma menti quando ti conviene.', pt: 'Você exige honestidade dos outros mas mente quando lhe convém.' }, options: [{ text: { es: 'Mis mentiras son diferentes: son necesarias o justificadas.', en: 'My lies are different: they\'re necessary or justified.', fr: 'Mes mensonges sont différents : ils sont nécessaires ou justifiés.', de: 'Meine Lügen sind anders: Sie sind notwendig oder gerechtfertigt.', it: 'Le mie bugie sono diverse: sono necessarie o giustificate.', pt: 'Minhas mentiras são diferentes: são necessárias ou justificadas.' }, dimension: 'H' }, { text: { es: 'No puedo exigir lo que no doy. Trabajo en ser más honesto/a.', en: 'I can\'t demand what I don\'t give. I\'m working on being more honest.', fr: 'Je ne peux pas exiger ce que je ne donne pas. Je travaille à être plus honnête.', de: 'Ich kann nicht verlangen, was ich nicht gebe. Ich arbeite daran, ehrlicher zu sein.', it: 'Non posso esigere ciò che non do. Sto lavorando per essere più onesto/a.', pt: 'Não posso exigir o que não dou. Estou trabalhando para ser mais honesto/a.' }, dimension: 'C' }, { text: { es: 'Es una de mis incoherencias. Lo reconozco.', en: 'It\'s one of my inconsistencies. I acknowledge it.', fr: 'C\'est l\'une de mes incohérences. Je le reconnais.', de: 'Es ist eine meiner Inkonsistenzen. Ich erkenne das an.', it: 'È una delle mie incoerenze. Lo riconosco.', pt: 'É uma das minhas incoerências. Reconheço isso.' }, dimension: 'A' }, { text: { es: 'Hay niveles. La honestidad absoluta tampoco es siempre correcta.', en: 'There are levels. Absolute honesty isn\'t always right either.', fr: 'Il y a des niveaux. L\'honnêteté absolue n\'est pas toujours correcte non plus.', de: 'Es gibt Ebenen. Absolute Ehrlichkeit ist auch nicht immer richtig.', it: 'Ci sono livelli. Anche l\'onestà assoluta non è sempre giusta.', pt: 'Há níveis. A honestidade absoluta também nem sempre é correta.' }, dimension: 'F' }] },
        { id: 4, situation: { es: 'Defiendes el medio ambiente pero tomas decisiones poco sostenibles frecuentemente.', en: 'You defend the environment but frequently make unsustainable choices.', fr: 'Tu défends l\'environnement mais tu prends fréquemment des décisions peu durables.', de: 'Du verteidigst die Umwelt, triffst aber häufig wenig nachhaltige Entscheidungen.', it: 'Difendi l\'ambiente ma prendi frequentemente decisioni poco sostenibili.', pt: 'Você defende o meio ambiente mas frequentemente toma decisões pouco sustentáveis.' }, options: [{ text: { es: 'El problema es sistémico. Lo que yo haga individualmente cambia poco.', en: 'The problem is systemic. What I do individually changes little.', fr: 'Le problème est systémique. Ce que je fais individuellement change peu de choses.', de: 'Das Problem ist systemisch. Was ich individuell tue, ändert wenig.', it: 'Il problema è sistemico. Quello che faccio individualmente cambia poco.', pt: 'O problema é sistêmico. O que faço individualmente muda pouco.' }, dimension: 'H' }, { text: { es: 'Intento que mis acciones sean consistentes con mis valores, aunque no siempre logro.', en: 'I try to make my actions consistent with my values, even if I don\'t always succeed.', fr: 'J\'essaie de faire en sorte que mes actions soient cohérentes avec mes valeurs, même si je n\'y arrive pas toujours.', de: 'Ich versuche, meine Handlungen mit meinen Werten in Einklang zu bringen, auch wenn mir das nicht immer gelingt.', it: 'Cerco di far sì che le mie azioni siano coerenti con i miei valori, anche se non ci riesco sempre.', pt: 'Tento fazer com que minhas ações sejam consistentes com meus valores, mesmo que nem sempre consiga.' }, dimension: 'C' }, { text: { es: 'Hay una brecha real entre lo que defiendo y cómo vivo. Lo sé.', en: 'There\'s a real gap between what I defend and how I live. I know it.', fr: 'Il y a un vrai écart entre ce que je défends et comment je vis. Je le sais.', de: 'Es gibt eine echte Lücke zwischen dem, wofür ich eintrete, und wie ich lebe. Ich weiß es.', it: 'C\'è un divario reale tra ciò che difendo e come vivo. Lo so.', pt: 'Há uma lacuna real entre o que defendo e como vivo. Eu sei disso.' }, dimension: 'A' }, { text: { es: 'La perfección no es el objetivo. Hacer algo es mejor que hacer nada.', en: 'Perfection isn\'t the goal. Doing something is better than doing nothing.', fr: 'La perfection n\'est pas l\'objectif. Faire quelque chose vaut mieux que ne rien faire.', de: 'Perfektion ist nicht das Ziel. Etwas zu tun ist besser als nichts zu tun.', it: 'La perfezione non è l\'obiettivo. Fare qualcosa è meglio di non fare nulla.', pt: 'A perfeição não é o objetivo. Fazer algo é melhor do que não fazer nada.' }, dimension: 'F' }] },
        { id: 5, situation: { es: 'Juzgas a otros por gastar de más, pero tú gastas en cosas que "valen la pena".', en: 'You judge others for overspending, but you spend on things that "are worth it".', fr: 'Tu juges les autres pour leurs dépenses excessives, mais toi tu dépenses pour des choses qui "valent la peine".', de: 'Du urteilst über andere für übermäßige Ausgaben, gibst aber selbst für Dinge aus, die "es wert sind".', it: 'Giudichi gli altri per spendere troppo, ma tu spendi per cose che "valgono la pena".', pt: 'Você julga os outros por gastar demais, mas você gasta em coisas que "valem a pena".' }, options: [{ text: { es: 'Lo mío son inversiones; lo de ellos es derroche.', en: 'Mine are investments; theirs is waste.', fr: 'Ce que je dépense, ce sont des investissements ; ce qu\'ils dépensent, c\'est du gaspillage.', de: 'Meine Ausgaben sind Investitionen; ihre sind Verschwendung.', it: 'Le mie spese sono investimenti; le loro sono sperperi.', pt: 'As minhas são investimentos; as deles são desperdício.' }, dimension: 'H' }, { text: { es: 'Si juzgo el gasto de otros, tengo que aplicar los mismos criterios al mío.', en: 'If I judge others\' spending, I have to apply the same criteria to mine.', fr: 'Si je juge les dépenses des autres, je dois appliquer les mêmes critères aux miennes.', de: 'Wenn ich die Ausgaben anderer beurteile, muss ich dieselben Kriterien auf meine eigenen anwenden.', it: 'Se giudico le spese degli altri, devo applicare gli stessi criteri alle mie.', pt: 'Se julgo os gastos dos outros, tenho que aplicar os mesmos critérios aos meus.' }, dimension: 'C' }, { text: { es: 'Reconozco que tengo estándares dobles en este tema.', en: 'I recognize I have double standards on this.', fr: 'Je reconnais que j\'ai deux poids deux mesures sur ce sujet.', de: 'Ich erkenne, dass ich in diesem Bereich doppelte Standards habe.', it: 'Riconosco di avere un doppio standard su questo tema.', pt: 'Reconheço que tenho dois pesos e duas medidas nesse assunto.' }, dimension: 'A' }, { text: { es: 'No todo gasto es igual. El contexto y la prioridad importan.', en: 'Not all spending is the same. Context and priority matter.', fr: 'Toutes les dépenses ne sont pas égales. Le contexte et la priorité comptent.', de: 'Nicht alle Ausgaben sind gleich. Kontext und Priorität sind wichtig.', it: 'Non tutta la spesa è uguale. Il contesto e la priorità contano.', pt: 'Nem todo gasto é igual. O contexto e a prioridade importam.' }, dimension: 'F' }] },
        { id: 6, situation: { es: 'Dices que valoras la privacidad pero hablas de la vida privada de otros regularmente.', en: 'You say you value privacy but regularly talk about others\' private lives.', fr: 'Tu dis que tu valorises la vie privée mais tu parles régulièrement de la vie privée des autres.', de: 'Du sagst, du schätzt Privatsphäre, redest aber regelmäßig über das Privatleben anderer.', it: 'Dici di valorizzare la privacy ma parli regolarmente della vita privata degli altri.', pt: 'Você diz valorizar a privacidade mas fala regularmente sobre a vida privada dos outros.' }, options: [{ text: { es: 'Yo hablo de hechos, no de rumores. Es diferente.', en: 'I talk about facts, not rumors. It\'s different.', fr: 'Je parle de faits, pas de rumeurs. C\'est différent.', de: 'Ich rede über Fakten, nicht über Gerüchte. Das ist anders.', it: 'Parlo di fatti, non di voci. È diverso.', pt: 'Eu falo de fatos, não de rumores. É diferente.' }, dimension: 'H' }, { text: { es: 'Si valoro la privacidad, no debería hablar de la vida de otros sin su permiso.', en: 'If I value privacy, I shouldn\'t talk about others\' lives without their permission.', fr: 'Si je valorise la vie privée, je ne devrais pas parler de la vie des autres sans leur permission.', de: 'Wenn ich Privatsphäre schätze, sollte ich nicht ohne Erlaubnis über das Leben anderer reden.', it: 'Se valuto la privacy, non dovrei parlare della vita degli altri senza il loro permesso.', pt: 'Se valorizo a privacidade, não devo falar sobre a vida dos outros sem sua permissão.' }, dimension: 'C' }, { text: { es: 'Sí, hay inconsistencia. No es mi mejor rasgo.', en: 'Yes, there\'s inconsistency. It\'s not my best trait.', fr: 'Oui, il y a une incohérence. Ce n\'est pas mon meilleur trait.', de: 'Ja, es gibt eine Inkonsistenz. Es ist nicht meine beste Eigenschaft.', it: 'Sì, c\'è incoerenza. Non è il mio tratto migliore.', pt: 'Sim, há inconsistência. Não é minha melhor característica.' }, dimension: 'A' }, { text: { es: 'Compartir información no siempre viola la privacidad. Depende del contexto.', en: 'Sharing information doesn\'t always violate privacy. It depends on context.', fr: 'Partager des informations ne viole pas toujours la vie privée. Ça dépend du contexte.', de: 'Das Teilen von Informationen verletzt nicht immer die Privatsphäre. Es hängt vom Kontext ab.', it: 'Condividere informazioni non viola sempre la privacy. Dipende dal contesto.', pt: 'Compartilhar informações nem sempre viola a privacidade. Depende do contexto.' }, dimension: 'F' }] },
        { id: 7, situation: { es: 'Predicas el trabajo duro pero usas atajos cuando nadie mira.', en: 'You preach hard work but take shortcuts when no one is watching.', fr: 'Tu prêches le travail acharné mais tu prends des raccourcis quand personne ne regarde.', de: 'Du predigst harte Arbeit, nimmst aber Abkürzungen, wenn niemand zuschaut.', it: 'Predichi il lavoro duro ma prendi scorciatoie quando nessuno guarda.', pt: 'Você prega o trabalho duro mas usa atalhos quando ninguém está vendo.' }, options: [{ text: { es: 'Los atajos eficientes no son lo mismo que la pereza.', en: 'Efficient shortcuts aren\'t the same as laziness.', fr: 'Les raccourcis efficaces ne sont pas la même chose que la paresse.', de: 'Effiziente Abkürzungen sind nicht dasselbe wie Faulheit.', it: 'Le scorciatoie efficienti non sono la stessa cosa della pigrizia.', pt: 'Atalhos eficientes não são o mesmo que preguiça.' }, dimension: 'H' }, { text: { es: 'Si predico algo, necesito estar dispuesto/a a hacerlo yo también.', en: 'If I preach something, I need to be willing to do it myself too.', fr: 'Si je prêche quelque chose, je dois être prêt(e) à le faire moi-même aussi.', de: 'Wenn ich etwas predige, muss ich bereit sein, es selbst zu tun.', it: 'Se predico qualcosa, devo essere disposto/a a farlo anche io.', pt: 'Se prego algo, preciso estar disposto/a a fazê-lo também.' }, dimension: 'C' }, { text: { es: 'No voy a mentir: no siempre practico lo que predico.', en: 'I\'m not going to lie: I don\'t always practice what I preach.', fr: 'Je ne vais pas mentir : je ne pratique pas toujours ce que je prêche.', de: 'Ich werde nicht lügen: Ich praktiziere nicht immer, was ich predige.', it: 'Non lo negherò: non pratico sempre quello che predico.', pt: 'Não vou mentir: não pratico sempre o que prego.' }, dimension: 'A' }, { text: { es: 'La adaptabilidad y los atajos inteligentes no contradicen el trabajo duro.', en: 'Adaptability and smart shortcuts don\'t contradict hard work.', fr: 'L\'adaptabilité et les raccourcis intelligents ne contredisent pas le travail acharné.', de: 'Anpassungsfähigkeit und intelligente Abkürzungen widersprechen der harten Arbeit nicht.', it: 'L\'adattabilità e le scorciatoie intelligenti non contraddicono il lavoro duro.', pt: 'Adaptabilidade e atalhos inteligentes não contradizem o trabalho duro.' }, dimension: 'F' }] },
        { id: 8, situation: { es: 'Criticas el consumismo mientras compras artículos de marca regularmente.', en: 'You criticize consumerism while regularly buying branded items.', fr: 'Tu critiques le consumérisme tout en achetant régulièrement des articles de marque.', de: 'Du kritisierst Konsumismus, kaufst aber regelmäßig Markenartikel.', it: 'Critichi il consumismo mentre acquisti regolarmente articoli di marca.', pt: 'Você critica o consumismo enquanto compra artigos de marca regularmente.' }, options: [{ text: { es: 'Hay marcas que valen y que no son consumismo vacío.', en: 'There are brands that have value and aren\'t empty consumerism.', fr: 'Il y a des marques qui valent quelque chose et qui ne sont pas du consumérisme vide.', de: 'Es gibt Marken, die ihren Wert haben und kein leerer Konsumismus sind.', it: 'Ci sono marchi che valgono e che non sono consumismo vuoto.', pt: 'Há marcas que valem e que não são consumismo vazio.' }, dimension: 'H' }, { text: { es: 'Si critico el consumismo, tengo que revisar mis propios patrones de compra.', en: 'If I criticize consumerism, I have to review my own buying patterns.', fr: 'Si je critique le consumérisme, je dois revoir mes propres habitudes d\'achat.', de: 'Wenn ich Konsumismus kritisiere, muss ich meine eigenen Kaufmuster überprüfen.', it: 'Se critico il consumismo, devo rivedere i miei stessi schemi di acquisto.', pt: 'Se critico o consumismo, tenho que revisar meus próprios padrões de compra.' }, dimension: 'C' }, { text: { es: 'Es una de mis contradicciones más obvias. Lo acepto.', en: 'It\'s one of my most obvious contradictions. I accept it.', fr: 'C\'est l\'une de mes contradictions les plus évidentes. Je l\'accepte.', de: 'Es ist eine meiner offensichtlichsten Widersprüche. Ich akzeptiere es.', it: 'È una delle mie contraddizioni più evidenti. La accetto.', pt: 'É uma das minhas contradições mais óbvias. Aceito isso.' }, dimension: 'A' }, { text: { es: 'No todo consumo es consumismo. Se puede ser crítico y también comprar.', en: 'Not all consumption is consumerism. You can be critical and still buy things.', fr: 'Tout consumo n\'est pas du consumérisme. On peut être critique et aussi acheter.', de: 'Nicht jeder Konsum ist Konsumismus. Man kann kritisch sein und trotzdem kaufen.', it: 'Non tutto il consumo è consumismo. Si può essere critici e anche comprare.', pt: 'Nem todo consumo é consumismo. Pode-se ser crítico e também comprar.' }, dimension: 'F' }] },
        { id: 9, situation: { es: 'Dices que no te importa lo que piensen los demás pero cambias tu comportamiento según el contexto social.', en: 'You say you don\'t care what others think but change your behavior based on social context.', fr: 'Tu dis que tu ne te soucies pas de ce que les autres pensent mais tu changes ton comportement selon le contexte social.', de: 'Du sagst, es ist dir egal, was andere denken, änderst aber dein Verhalten je nach sozialem Kontext.', it: 'Dici che non ti importa cosa pensano gli altri ma cambi il tuo comportamento in base al contesto sociale.', pt: 'Você diz que não se importa com o que os outros pensam mas muda seu comportamento conforme o contexto social.' }, options: [{ text: { es: 'Eso es solo inteligencia social, no hipocresía.', en: 'That\'s just social intelligence, not hypocrisy.', fr: 'C\'est juste de l\'intelligence sociale, pas de l\'hypocrisie.', de: 'Das ist nur soziale Intelligenz, keine Heuchelei.', it: 'È solo intelligenza sociale, non ipocrisia.', pt: 'Isso é apenas inteligência social, não hipocrisia.' }, dimension: 'H' }, { text: { es: 'Si realmente no me importara, actuaría igual en todos los contextos.', en: 'If I truly didn\'t care, I would act the same in all contexts.', fr: 'Si ça ne m\'importait vraiment pas, j\'agirais de la même façon dans tous les contextes.', de: 'Wenn es mir wirklich egal wäre, würde ich in allen Kontexten gleich handeln.', it: 'Se davvero non me ne importasse, agirei allo stesso modo in tutti i contesti.', pt: 'Se realmente não me importasse, agiria da mesma forma em todos os contextos.' }, dimension: 'C' }, { text: { es: 'Sí, la verdad es que sí me importa lo que piensan. Me autoengaño a veces.', en: 'Yes, the truth is I do care what they think. I self-deceive sometimes.', fr: 'Oui, la vérité c\'est que ça m\'importe ce qu\'ils pensent. Je me trompe parfois moi-même.', de: 'Ja, die Wahrheit ist, dass mir doch wichtig ist, was sie denken. Manchmal täusche ich mich selbst.', it: 'Sì, la verità è che mi importa cosa pensano. A volte mi autoinganni.', pt: 'Sim, a verdade é que me importa sim o que pensam. Às vezes me enganô a mim mesmo/a.' }, dimension: 'A' }, { text: { es: 'Adaptar el comportamiento al contexto es madurez, no incoherencia.', en: 'Adapting behavior to context is maturity, not inconsistency.', fr: 'Adapter son comportement au contexte, c\'est de la maturité, pas de l\'incohérence.', de: 'Das Verhalten an den Kontext anzupassen ist Reife, keine Inkonsistenz.', it: 'Adattare il comportamento al contesto è maturità, non incoerenza.', pt: 'Adaptar o comportamento ao contexto é maturidade, não incoerência.' }, dimension: 'F' }] },
        { id: 10, situation: { es: '¿Cómo describirías tu relación entre lo que dices y lo que haces?', en: 'How would you describe the relationship between what you say and what you do?', fr: 'Comment décrirais-tu la relation entre ce que tu dis et ce que tu fais ?', de: 'Wie würdest du die Beziehung zwischen dem, was du sagst, und dem, was du tust, beschreiben?', it: 'Come descriveresti il rapporto tra quello che dici e quello che fai?', pt: 'Como você descreveria a relação entre o que você diz e o que você faz?' }, options: [{ text: { es: 'Generalmente consistente, con excepciones justificadas.', en: 'Generally consistent, with justified exceptions.', fr: 'Généralement cohérent(e), avec des exceptions justifiées.', de: 'Im Allgemeinen konsistent, mit gerechtfertigten Ausnahmen.', it: 'Generalmente coerente, con eccezioni giustificate.', pt: 'Geralmente consistente, com exceções justificadas.' }, dimension: 'H' }, { text: { es: 'Aspiro a la coherencia y cuando fallo, me lo tomo en serio.', en: 'I aspire to coherence and when I fail, I take it seriously.', fr: 'J\'aspire à la cohérence et quand j\'échoue, je le prends au sérieux.', de: 'Ich strebe nach Kohärenz und wenn ich scheitere, nehme ich es ernst.', it: 'Aspiro alla coerenza e quando fallisco, lo prendo sul serio.', pt: 'Aspiro à coerência e quando falho, levo a sério.' }, dimension: 'C' }, { text: { es: 'Hay brechas. Las veo y trabajo en ellas.', en: 'There are gaps. I see them and work on them.', fr: 'Il y a des écarts. Je les vois et j\'y travaille.', de: 'Es gibt Lücken. Ich sehe sie und arbeite daran.', it: 'Ci sono divari. Li vedo e ci lavoro su.', pt: 'Há lacunas. As vejo e trabalho nelas.' }, dimension: 'A' }, { text: { es: 'Ningún ser humano es perfectamente consistente. Lo importante es la dirección.', en: 'No human being is perfectly consistent. What matters is the direction.', fr: 'Aucun être humain n\'est parfaitement cohérent. Ce qui compte, c\'est la direction.', de: 'Kein Mensch ist vollkommen konsistent. Was zählt, ist die Richtung.', it: 'Nessun essere umano è perfettamente coerente. Ciò che conta è la direzione.', pt: 'Nenhum ser humano é perfeitamente consistente. O que importa é a direção.' }, dimension: 'F' }] },
      ],
      characters: [
        { name: { es: 'El Hipócrita Clásico', en: 'The Classic Hypocrite', fr: 'L\'Hypocrite Classique', de: 'Der Klassische Heuchler', it: 'L\'Ipocrita Classico', pt: 'O Hipócrita Clássico' }, dimensions: ['H'], photo: '/characters/hypocrite.jpg', description: { es: 'Tiene una norma para él y otra para los demás.', en: 'Has one standard for themselves and another for everyone else.', fr: 'A une norme pour lui-même et une autre pour les autres.', de: 'Hat einen Standard für sich selbst und einen anderen für alle anderen.', it: 'Ha uno standard per sé e un altro per gli altri.', pt: 'Tem um padrão para si mesmo e outro para os demais.' }, philosophy: { es: 'No eres consciente de tu doble estándar — o lo justificas tan bien que se convierte en verdad para ti. Cada excepción para ti misma/o tiene una razón. Las reglas generales son para los demás.', en: 'You\'re not aware of your double standard — or you justify it so well it becomes truth for you. Every exception for yourself has a reason. General rules are for others.', fr: 'Tu n\'es pas conscient(e) de ton double standard — ou tu le justifies si bien qu\'il devient vérité pour toi. Chaque exception pour toi-même a une raison. Les règles générales sont pour les autres.', de: 'Du bist dir deines doppelten Standards nicht bewusst — oder du rechtfertigst ihn so gut, dass er für dich zur Wahrheit wird. Jede Ausnahme für dich selbst hat einen Grund. Allgemeine Regeln gelten für andere.', it: 'Non sei consapevole del tuo doppio standard — o lo giustifichi così bene che diventa verità per te. Ogni eccezione per te stesso/a ha una ragione. Le regole generali sono per gli altri.', pt: 'Você não está ciente do seu duplo padrão — ou o justifica tão bem que se torna verdade para você. Cada exceção para si mesmo tem uma razão. As regras gerais são para os outros.' } },
        { name: { es: 'El Coherente', en: 'The Coherent One', fr: 'Le Cohérent', de: 'Der Kohärente', it: 'Il Coerente', pt: 'O Coerente' }, dimensions: ['C'], photo: '/characters/coherent.jpg', description: { es: 'Vive lo que predica. No siempre fácil, pero siempre intencional.', en: 'Lives what they preach. Not always easy, but always intentional.', fr: 'Vit ce qu\'il prêche. Pas toujours facile, mais toujours intentionnel.', de: 'Lebt, was er predigt. Nicht immer einfach, aber immer absichtlich.', it: 'Vive quello che predica. Non sempre facile, ma sempre intenzionale.', pt: 'Vive o que prega. Nem sempre fácil, mas sempre intencional.' }, philosophy: { es: 'Para ti, la integridad es práctica diaria, no solo discurso. Cuando ves una brecha entre lo que dices y lo que haces, actúas. Eso requiere un nivel de honestidad consigo mismo/a que no es común.', en: 'For you, integrity is daily practice, not just talk. When you see a gap between what you say and what you do, you act. That requires a level of self-honesty that isn\'t common.', fr: 'Pour toi, l\'intégrité est une pratique quotidienne, pas seulement un discours. Quand tu vois un écart entre ce que tu dis et ce que tu fais, tu agis. Cela demande un niveau d\'honnêteté envers soi-même qui n\'est pas courant.', de: 'Für dich ist Integrität tägliche Praxis, nicht nur Gerede. Wenn du eine Lücke zwischen dem, was du sagst, und dem, was du tust, siehst, handelst du. Das erfordert ein Maß an Selbstehrlichkeit, das nicht üblich ist.', it: 'Per te, l\'integrità è pratica quotidiana, non solo discorso. Quando vedi un divario tra quello che dici e quello che fai, agisci. Questo richiede un livello di onestà verso se stessi che non è comune.', pt: 'Para você, a integridade é prática diária, não apenas discurso. Quando vê uma lacuna entre o que diz e o que faz, age. Isso requer um nível de honestidade consigo mesmo que não é comum.' } },
        { name: { es: 'El Consciente de sus Contradicciones', en: 'The Contradiction-Aware', fr: 'Le Conscient de ses Contradictions', de: 'Der Widerspruchsbewusste', it: 'Il Consapevole delle Contraddizioni', pt: 'O Consciente das Contradições' }, dimensions: ['A'], photo: '/characters/contradiction-aware.jpg', description: { es: 'Sabe que tiene incoherencias y no pretende lo contrario.', en: 'Knows they have inconsistencies and doesn\'t pretend otherwise.', fr: 'Sait qu\'il a des incohérences et ne prétend pas le contraire.', de: 'Weiß, dass er Inkonsistenzen hat, und tut nicht so als ob nicht.', it: 'Sa di avere incoerenze e non finge il contrario.', pt: 'Sabe que tem incoerências e não finge o contrário.' }, philosophy: { es: 'Tu honestidad sobre tus propias contradicciones es en sí misma una forma de integridad. No pretendes ser perfecto/a — simplemente eres transparente sobre dónde estás. Eso ya es mucho.', en: 'Your honesty about your own contradictions is itself a form of integrity. You don\'t pretend to be perfect — you\'re simply transparent about where you are. That\'s already a lot.', fr: 'Ton honnêteté sur tes propres contradictions est en soi une forme d\'intégrité. Tu ne prétends pas être parfait(e) — tu es simplement transparent(e) sur où tu en es. C\'est déjà beaucoup.', de: 'Deine Ehrlichkeit über deine eigenen Widersprüche ist selbst eine Form von Integrität. Du tust nicht so, als wärst du perfekt — du bist einfach transparent darüber, wo du stehst. Das ist schon viel.', it: 'La tua onestà sulle tue stesse contraddizioni è in sé una forma di integrità. Non fingi di essere perfetto/a — sei semplicemente trasparente su dove ti trovi. Questo è già molto.', pt: 'Sua honestidade sobre suas próprias contradições é em si mesma uma forma de integridade. Você não finge ser perfeito/a — simplesmente é transparente sobre onde está. Isso já é muito.' } },
        { name: { es: 'El Contextual Flexible', en: 'The Flexible Contextualist', fr: 'Le Contextuel Flexible', de: 'Der Flexible Kontextualist', it: 'Il Contestuale Flessibile', pt: 'O Contextual Flexível' }, dimensions: ['F'], photo: '/characters/contextual.jpg', description: { es: 'Las reglas no son absolutas. Todo depende del contexto.', en: 'Rules aren\'t absolute. Everything depends on context.', fr: 'Les règles ne sont pas absolues. Tout dépend du contexte.', de: 'Regeln sind nicht absolut. Alles hängt vom Kontext ab.', it: 'Le regole non sono assolute. Tutto dipende dal contesto.', pt: 'As regras não são absolutas. Tudo depende do contexto.' }, philosophy: { es: 'Para ti, la consistencia perfecta es una fantasía. El mundo es complejo, los contextos importan y la flexibilidad no es hipocresía — es madurez. El peligro es cuando la flexibilidad se convierte en excusa.', en: 'For you, perfect consistency is a fantasy. The world is complex, contexts matter and flexibility isn\'t hypocrisy — it\'s maturity. The danger is when flexibility becomes an excuse.', fr: 'Pour toi, la cohérence parfaite est une fantaisie. Le monde est complexe, les contextes comptent et la flexibilité n\'est pas de l\'hypocrisie — c\'est de la maturité. Le danger, c\'est quand la flexibilité devient une excuse.', de: 'Für dich ist vollkommene Konsistenz eine Fantasie. Die Welt ist komplex, Kontexte sind wichtig und Flexibilität ist keine Heuchelei — es ist Reife. Die Gefahr besteht, wenn Flexibilität zur Ausrede wird.', it: 'Per te, la coerenza perfetta è una fantasia. Il mondo è complesso, i contesti contano e la flessibilità non è ipocrisia — è maturità. Il pericolo è quando la flessibilità diventa una scusa.', pt: 'Para você, a consistência perfeita é uma fantasia. O mundo é complexo, os contextos importam e a flexibilidade não é hipocrisia — é maturidade. O perigo é quando a flexibilidade vira desculpa.' } },
        { name: { es: 'El Autoengañado Elegante', en: 'The Elegant Self-Deceiver', fr: 'Le Trompeur Élégant de Lui-Même', de: 'Der Elegante Selbstbetrüger', it: 'L\'Autoingannato Elegante', pt: 'O Autoiludido Elegante' }, dimensions: ['H', 'F'], photo: '/characters/self-deceived.jpg', description: { es: 'Tiene respuesta para todo. Sus excepciones siempre tienen justificación.', en: 'Has an answer for everything. Their exceptions always have justification.', fr: 'A une réponse à tout. Ses exceptions ont toujours une justification.', de: 'Hat eine Antwort auf alles. Seine Ausnahmen haben immer eine Begründung.', it: 'Ha una risposta per tutto. Le sue eccezioni hanno sempre una giustificazione.', pt: 'Tem resposta para tudo. Suas exceções sempre têm justificativa.' }, philosophy: { es: 'Eres el tipo más sofisticado de hipócrita: el que tiene una narrativa coherente para cada inconsistencia. No mientes — simplemente construyes marcos que hacen que tus excepciones siempre parezcan razonables.', en: 'You\'re the most sophisticated type of hypocrite: the one with a coherent narrative for every inconsistency. You don\'t lie — you simply build frameworks that make your exceptions always seem reasonable.', fr: 'Tu es le type d\'hypocrite le plus sophistiqué : celui qui a un récit cohérent pour chaque inconsistance. Tu ne mens pas — tu construis simplement des cadres qui font que tes exceptions semblent toujours raisonnables.', de: 'Du bist der ausgefeilteste Typ von Heuchler: derjenige, der für jede Inkonsistenz eine kohärente Erzählung hat. Du lügst nicht — du baust einfach Rahmen, die deine Ausnahmen immer vernünftig erscheinen lassen.', it: 'Sei il tipo più sofisticato di ipocrita: quello che ha una narrativa coerente per ogni incoerenza. Non menti — semplicemente costruisci quadri che fanno sì che le tue eccezioni sembrino sempre ragionevoli.', pt: 'Você é o tipo mais sofisticado de hipócrita: aquele que tem uma narrativa coerente para cada inconsistência. Não mente — simplesmente constrói frameworks que fazem suas exceções sempre parecerem razoáveis.' } },
        { name: { es: 'El En Proceso', en: 'The Work in Progress', fr: 'Le En Cours de Processus', de: 'Der im Prozess Befindliche', it: 'Il In Elaborazione', pt: 'O Em Processo' }, dimensions: ['H', 'A'], photo: '/characters/in-process.jpg', description: { es: 'Ve sus hipocresías y trabaja en ellas, aunque despacio.', en: 'Sees their hypocrisies and works on them, albeit slowly.', fr: 'Voit ses hypocrisies et y travaille, même si c\'est lentement.', de: 'Sieht seine Heucheleien und arbeitet daran, wenn auch langsam.', it: 'Vede le sue ipocrisie e ci lavora su, anche se lentamente.', pt: 'Vê suas hipocrisias e trabalha nelas, embora lentamente.' }, philosophy: { es: 'La autoconciencia es el primer paso. Lo ves, lo nombras y a veces todavía caes en ello. Pero hay movimiento. La diferencia entre el hipócrita estático y el que crece es exactamente ese reconocimiento.', en: 'Self-awareness is the first step. You see it, you name it and sometimes you still fall into it. But there\'s movement. The difference between the static hypocrite and the growing one is exactly that recognition.', fr: 'La conscience de soi est la première étape. Tu le vois, tu le nommes et parfois tu y tombes encore. Mais il y a un mouvement. La différence entre l\'hypocrite statique et celui qui grandit, c\'est exactement cette reconnaissance.', de: 'Selbstbewusstsein ist der erste Schritt. Du siehst es, du nennst es und manchmal fällst du noch darauf herein. Aber es gibt Bewegung. Der Unterschied zwischen dem statischen Heuchler und dem, der wächst, ist genau diese Anerkennung.', it: 'La consapevolezza di sé è il primo passo. Lo vedi, lo nomini e a volte ci ricaschi ancora. Ma c\'è movimento. La differenza tra l\'ipocrita statico e quello che cresce è esattamente quel riconoscimento.', pt: 'A autoconsciência é o primeiro passo. Você vê, nomeia e às vezes ainda cai nisso. Mas há movimento. A diferença entre o hipócrita estático e o que cresce é exatamente esse reconhecimento.' } },
        { name: { es: 'El Realista Honesto', en: 'The Honest Realist', fr: 'Le Réaliste Honnête', de: 'Der Ehrliche Realist', it: 'Il Realista Onesto', pt: 'O Realista Honesto' }, dimensions: ['A', 'F'], photo: '/characters/realistic-honest.jpg', description: { es: 'Sabe que es imperfecto y no juzga a los demás por el mismo motivo.', en: 'Knows they\'re imperfect and doesn\'t judge others for the same reason.', fr: 'Sait qu\'il est imparfait et ne juge pas les autres pour la même raison.', de: 'Weiß, dass er unvollkommen ist, und urteilt aus demselben Grund nicht über andere.', it: 'Sa di essere imperfetto e non giudica gli altri per lo stesso motivo.', pt: 'Sabe que é imperfeito e não julga os outros pelo mesmo motivo.' }, philosophy: { es: 'Reconoces tus brechas y por eso también eres compasivo/a con las de los demás. No eres duro/a con tu hipocresía ni con la ajena — simplemente la reconoces como parte de la condición humana.', en: 'You recognize your gaps and so you\'re also compassionate with those of others. You\'re not harsh with your own hypocrisy or others\' — you simply recognize it as part of the human condition.', fr: 'Tu reconnais tes lacunes et c\'est pourquoi tu es aussi compatissant(e) avec celles des autres. Tu n\'es pas dur(e) avec ton hypocrisie ni avec celle des autres — tu la reconnais simplement comme faisant partie de la condition humaine.', de: 'Du erkennst deine Lücken und bist deshalb auch mitfühlend gegenüber denen anderer. Du bist nicht hart zu deiner eigenen Heuchelei oder der anderer — du erkennst sie einfach als Teil der menschlichen Natur.', it: 'Riconosci i tuoi divari e per questo sei anche compassionevole con quelli degli altri. Non sei duro/a con la tua ipocrisia né con quella altrui — la riconosci semplicemente come parte della condizione umana.', pt: 'Você reconhece suas lacunas e por isso também é compassivo/a com as dos outros. Não é duro/a com sua hipocrisia nem com a alheia — simplesmente a reconhece como parte da condição humana.' } },
        { name: { es: 'El Íntegro en Movimiento', en: 'Integrity in Motion', fr: 'L\'Intègre en Mouvement', de: 'Die Integrität in Bewegung', it: 'L\'Integro in Movimento', pt: 'A Integridade em Movimento' }, dimensions: ['C', 'A'], photo: '/characters/integrity.jpg', description: { es: 'Aspira a la coherencia y cuando falla, lo reconoce y ajusta.', en: 'Aspires to coherence and when they fail, recognizes it and adjusts.', fr: 'Aspire à la cohérence et quand il échoue, il le reconnaît et s\'ajuste.', de: 'Strebt nach Kohärenz und erkennt und passt an, wenn er scheitert.', it: 'Aspira alla coerenza e quando fallisce, lo riconosce e si adegua.', pt: 'Aspira à coerência e quando falha, reconhece e ajusta.' }, philosophy: { es: 'Combinas la aspiración a la coherencia con la honestidad sobre los momentos en que no llegas. Eso crea una integridad dinámica: no perfecta, pero genuina. Es el tipo más sostenible de honestidad.', en: 'You combine the aspiration to coherence with honesty about the moments when you fall short. That creates a dynamic integrity: not perfect, but genuine. It\'s the most sustainable kind of honesty.', fr: 'Tu combines l\'aspiration à la cohérence avec l\'honnêteté sur les moments où tu n\'y arrives pas. Cela crée une intégrité dynamique : pas parfaite, mais authentique. C\'est le type d\'honnêteté le plus durable.', de: 'Du kombinierst das Streben nach Kohärenz mit Ehrlichkeit über die Momente, in denen du nicht erreichst. Das schafft eine dynamische Integrität: nicht perfekt, aber echt. Das ist die nachhaltigste Art von Ehrlichkeit.', it: 'Combini l\'aspirazione alla coerenza con l\'onestà sui momenti in cui non ci riesci. Questo crea un\'integrità dinamica: non perfetta, ma genuina. È il tipo più sostenibile di onestà.', pt: 'Você combina a aspiração à coerência com a honestidade sobre os momentos em que não alcança. Isso cria uma integridade dinâmica: não perfeita, mas genuína. É o tipo mais sustentável de honestidade.' } },
      ],
    },
    create: {
      slug: 'hypocrite',
      title: { es: '¿Qué tan hipócrita eres?', en: 'How much of a hypocrite are you?', fr: 'À quel point es-tu hypocrite ?', de: 'Wie heuchlerisch bist du?', it: 'Quanto sei ipocrita?', pt: 'O quanto você é hipócrita?' },
      description: { es: 'Todos predicamos algo que no siempre practicamos. ¿Qué tan grande es tu brecha?', en: 'We all preach things we don\'t always practice. How big is your gap?', fr: 'Nous prêchons tous des choses que nous ne pratiquons pas toujours. Quelle est la taille de ton écart ?', de: 'Wir alle predigen Dinge, die wir nicht immer praktizieren. Wie groß ist deine Lücke?', it: 'Tutti predichiamo qualcosa che non pratichiamo sempre. Quanto è grande il tuo divario?', pt: 'Todos pregamos algo que nem sempre praticamos. O quão grande é a sua lacuna?' },
      scenarioLabel: { es: 'Escenario', en: 'Scenario', fr: 'Scénario', de: 'Szenario', it: 'Scenario', pt: 'Cenário' },
      categoryId: catMap['moral'],
      sortOrder: 3,
      dimensionLabels: {
        es: { H: 'Hipocresía', C: 'Coherencia', A: 'Autoconciencia', F: 'Flexibilidad' },
        en: { H: 'Hypocrisy', C: 'Coherence', A: 'Self-awareness', F: 'Flexibility' },
        fr: { H: 'Hypocrisie', C: 'Cohérence', A: 'Conscience de soi', F: 'Flexibilité' },
        de: { H: 'Heuchelei', C: 'Kohärenz', A: 'Selbstbewusstsein', F: 'Flexibilität' },
        it: { H: 'Ipocrisia', C: 'Coerenza', A: 'Autoconsapevolezza', F: 'Flessibilità' },
        pt: { H: 'Hipocrisia', C: 'Coerência', A: 'Autoconhecimento', F: 'Flexibilidade' },
      },
      questions: [
        { id: 1, situation: { es: 'Criticas a la gente que llega tarde, pero tú llegas tarde regularmente.', en: 'You criticize people who are late, but you\'re late regularly yourself.', fr: 'Tu critiques les gens qui arrivent en retard, mais toi-même tu arrives régulièrement en retard.', de: 'Du kritisierst Menschen, die zu spät kommen, kommst aber selbst regelmäßig zu spät.', it: 'Critichi le persone che arrivano in ritardo, ma tu stesso/a arrivi regolarmente in ritardo.', pt: 'Você critica as pessoas que chegam atrasadas, mas você mesmo chega atrasado regularmente.' }, options: [{ text: { es: 'Sí, lo hago, pero en mi caso siempre hay razones válidas.', en: 'Yes, I do, but in my case there are always valid reasons.', fr: 'Oui, je le fais, mais dans mon cas il y a toujours des raisons valables.', de: 'Ja, das tue ich, aber in meinem Fall gibt es immer gültige Gründe.', it: 'Sì, lo faccio, ma nel mio caso ci sono sempre ragioni valide.', pt: 'Sim, faço isso, mas no meu caso sempre há razões válidas.' }, dimension: 'H' }, { text: { es: 'Si critico algo, trabajo para no hacerlo yo también.', en: 'If I criticize something, I work to not do it myself either.', fr: 'Si je critique quelque chose, je travaille à ne pas le faire moi-même non plus.', de: 'Wenn ich etwas kritisiere, arbeite ich daran, es selbst auch nicht zu tun.', it: 'Se critico qualcosa, lavoro per non farlo io stesso/a.', pt: 'Se critico algo, trabalho para não fazer o mesmo.' }, dimension: 'C' }, { text: { es: 'Lo reconozco: soy inconsistente en este tema.', en: 'I admit it: I\'m inconsistent on this.', fr: 'Je le reconnais : je suis incohérent(e) sur ce sujet.', de: 'Ich gebe es zu: Ich bin in dieser Hinsicht inkonsistent.', it: 'Lo riconosco: sono incoerente su questo tema.', pt: 'Reconheço: sou inconsistente nesse assunto.' }, dimension: 'A' }, { text: { es: 'Depende del contexto. La puntualidad no siempre tiene el mismo peso.', en: 'It depends on context. Punctuality doesn\'t always carry the same weight.', fr: 'Ça dépend du contexte. La ponctualité n\'a pas toujours le même poids.', de: 'Es hängt vom Kontext ab. Pünktlichkeit hat nicht immer das gleiche Gewicht.', it: 'Dipende dal contesto. La puntualità non ha sempre lo stesso peso.', pt: 'Depende do contexto. A pontualidade nem sempre tem o mesmo peso.' }, dimension: 'F' }] },
        { id: 2, situation: { es: 'Publicas contenido sobre salud mental mientras ignoras tus propias necesidades emocionales.', en: 'You post content about mental health while ignoring your own emotional needs.', fr: 'Tu publies du contenu sur la santé mentale tout en ignorant tes propres besoins émotionnels.', de: 'Du postest Inhalte über psychische Gesundheit, während du deine eigenen emotionalen Bedürfnisse ignorierst.', it: 'Pubblichi contenuti sulla salute mentale mentre ignori i tuoi stessi bisogni emotivi.', pt: 'Você posta conteúdo sobre saúde mental enquanto ignora suas próprias necessidades emocionais.' }, options: [{ text: { es: 'El contenido es útil para otros aunque yo no lo practique perfectamente.', en: 'The content is useful for others even if I don\'t practice it perfectly myself.', fr: 'Le contenu est utile pour les autres même si je ne le pratique pas parfaitement moi-même.', de: 'Der Inhalt ist für andere nützlich, auch wenn ich es nicht perfekt selbst praktiziere.', it: 'Il contenuto è utile per gli altri anche se io non lo pratico perfettamente.', pt: 'O conteúdo é útil para os outros mesmo que eu não o pratique perfeitamente.' }, dimension: 'H' }, { text: { es: 'Si lo publico, intento aplicarlo. Si no puedo, no lo publico.', en: 'If I post it, I try to apply it. If I can\'t, I don\'t post it.', fr: 'Si je le publie, j\'essaie de l\'appliquer. Si je ne peux pas, je ne le publie pas.', de: 'Wenn ich es poste, versuche ich es anzuwenden. Wenn ich das nicht kann, poste ich es nicht.', it: 'Se lo pubblico, cerco di applicarlo. Se non posso, non lo pubblico.', pt: 'Se publico, tento aplicar. Se não consigo, não publico.' }, dimension: 'C' }, { text: { es: 'Lo sé. Hay una brecha entre lo que digo y lo que hago.', en: 'I know. There\'s a gap between what I say and what I do.', fr: 'Je le sais. Il y a un écart entre ce que je dis et ce que je fais.', de: 'Ich weiß es. Es gibt eine Lücke zwischen dem, was ich sage, und dem, was ich tue.', it: 'Lo so. C\'è un divario tra quello che dico e quello che faccio.', pt: 'Eu sei. Há uma lacuna entre o que digo e o que faço.' }, dimension: 'A' }, { text: { es: 'Puedes saber la teoría y no aplicarla. No lo veo como hipocresía.', en: 'You can know the theory and not apply it. I don\'t see that as hypocrisy.', fr: 'On peut connaître la théorie sans l\'appliquer. Je ne vois pas ça comme de l\'hypocrisie.', de: 'Man kann die Theorie kennen und sie nicht anwenden. Ich sehe das nicht als Heuchelei.', it: 'Puoi conoscere la teoria senza applicarla. Non la vedo come ipocrisia.', pt: 'Você pode conhecer a teoria sem aplicá-la. Não vejo isso como hipocrisia.' }, dimension: 'F' }] },
        { id: 3, situation: { es: 'Exiges honestidad a los demás pero mientes cuando te conviene.', en: 'You demand honesty from others but lie when it suits you.', fr: 'Tu exiges l\'honnêteté des autres mais tu mens quand ça t\'arrange.', de: 'Du verlangst Ehrlichkeit von anderen, lügst aber, wenn es dir passt.', it: 'Esigi onestà dagli altri ma menti quando ti conviene.', pt: 'Você exige honestidade dos outros mas mente quando lhe convém.' }, options: [{ text: { es: 'Mis mentiras son diferentes: son necesarias o justificadas.', en: 'My lies are different: they\'re necessary or justified.', fr: 'Mes mensonges sont différents : ils sont nécessaires ou justifiés.', de: 'Meine Lügen sind anders: Sie sind notwendig oder gerechtfertigt.', it: 'Le mie bugie sono diverse: sono necessarie o giustificate.', pt: 'Minhas mentiras são diferentes: são necessárias ou justificadas.' }, dimension: 'H' }, { text: { es: 'No puedo exigir lo que no doy. Trabajo en ser más honesto/a.', en: 'I can\'t demand what I don\'t give. I\'m working on being more honest.', fr: 'Je ne peux pas exiger ce que je ne donne pas. Je travaille à être plus honnête.', de: 'Ich kann nicht verlangen, was ich nicht gebe. Ich arbeite daran, ehrlicher zu sein.', it: 'Non posso esigere ciò che non do. Sto lavorando per essere più onesto/a.', pt: 'Não posso exigir o que não dou. Estou trabalhando para ser mais honesto/a.' }, dimension: 'C' }, { text: { es: 'Es una de mis incoherencias. Lo reconozco.', en: 'It\'s one of my inconsistencies. I acknowledge it.', fr: 'C\'est l\'une de mes incohérences. Je le reconnais.', de: 'Es ist eine meiner Inkonsistenzen. Ich erkenne das an.', it: 'È una delle mie incoerenze. Lo riconosco.', pt: 'É uma das minhas incoerências. Reconheço isso.' }, dimension: 'A' }, { text: { es: 'Hay niveles. La honestidad absoluta tampoco es siempre correcta.', en: 'There are levels. Absolute honesty isn\'t always right either.', fr: 'Il y a des niveaux. L\'honnêteté absolue n\'est pas toujours correcte non plus.', de: 'Es gibt Ebenen. Absolute Ehrlichkeit ist auch nicht immer richtig.', it: 'Ci sono livelli. Anche l\'onestà assoluta non è sempre giusta.', pt: 'Há níveis. A honestidade absoluta também nem sempre é correta.' }, dimension: 'F' }] },
        { id: 4, situation: { es: 'Defiendes el medio ambiente pero tomas decisiones poco sostenibles frecuentemente.', en: 'You defend the environment but frequently make unsustainable choices.', fr: 'Tu défends l\'environnement mais tu prends fréquemment des décisions peu durables.', de: 'Du verteidigst die Umwelt, triffst aber häufig wenig nachhaltige Entscheidungen.', it: 'Difendi l\'ambiente ma prendi frequentemente decisioni poco sostenibili.', pt: 'Você defende o meio ambiente mas frequentemente toma decisões pouco sustentáveis.' }, options: [{ text: { es: 'El problema es sistémico. Lo que yo haga individualmente cambia poco.', en: 'The problem is systemic. What I do individually changes little.', fr: 'Le problème est systémique. Ce que je fais individuellement change peu de choses.', de: 'Das Problem ist systemisch. Was ich individuell tue, ändert wenig.', it: 'Il problema è sistemico. Quello che faccio individualmente cambia poco.', pt: 'O problema é sistêmico. O que faço individualmente muda pouco.' }, dimension: 'H' }, { text: { es: 'Intento que mis acciones sean consistentes con mis valores, aunque no siempre logro.', en: 'I try to make my actions consistent with my values, even if I don\'t always succeed.', fr: 'J\'essaie de faire en sorte que mes actions soient cohérentes avec mes valeurs, même si je n\'y arrive pas toujours.', de: 'Ich versuche, meine Handlungen mit meinen Werten in Einklang zu bringen, auch wenn mir das nicht immer gelingt.', it: 'Cerco di far sì che le mie azioni siano coerenti con i miei valori, anche se non ci riesco sempre.', pt: 'Tento fazer com que minhas ações sejam consistentes com meus valores, mesmo que nem sempre consiga.' }, dimension: 'C' }, { text: { es: 'Hay una brecha real entre lo que defiendo y cómo vivo. Lo sé.', en: 'There\'s a real gap between what I defend and how I live. I know it.', fr: 'Il y a un vrai écart entre ce que je défends et comment je vis. Je le sais.', de: 'Es gibt eine echte Lücke zwischen dem, wofür ich eintrete, und wie ich lebe. Ich weiß es.', it: 'C\'è un divario reale tra ciò che difendo e come vivo. Lo so.', pt: 'Há uma lacuna real entre o que defendo e como vivo. Eu sei disso.' }, dimension: 'A' }, { text: { es: 'La perfección no es el objetivo. Hacer algo es mejor que hacer nada.', en: 'Perfection isn\'t the goal. Doing something is better than doing nothing.', fr: 'La perfection n\'est pas l\'objectif. Faire quelque chose vaut mieux que ne rien faire.', de: 'Perfektion ist nicht das Ziel. Etwas zu tun ist besser als nichts zu tun.', it: 'La perfezione non è l\'obiettivo. Fare qualcosa è meglio di non fare nulla.', pt: 'A perfeição não é o objetivo. Fazer algo é melhor do que não fazer nada.' }, dimension: 'F' }] },
        { id: 5, situation: { es: 'Juzgas a otros por gastar de más, pero tú gastas en cosas que "valen la pena".', en: 'You judge others for overspending, but you spend on things that "are worth it".', fr: 'Tu juges les autres pour leurs dépenses excessives, mais toi tu dépenses pour des choses qui "valent la peine".', de: 'Du urteilst über andere für übermäßige Ausgaben, gibst aber selbst für Dinge aus, die "es wert sind".', it: 'Giudichi gli altri per spendere troppo, ma tu spendi per cose che "valgono la pena".', pt: 'Você julga os outros por gastar demais, mas você gasta em coisas que "valem a pena".' }, options: [{ text: { es: 'Lo mío son inversiones; lo de ellos es derroche.', en: 'Mine are investments; theirs is waste.', fr: 'Ce que je dépense, ce sont des investissements ; ce qu\'ils dépensent, c\'est du gaspillage.', de: 'Meine Ausgaben sind Investitionen; ihre sind Verschwendung.', it: 'Le mie spese sono investimenti; le loro sono sperperi.', pt: 'As minhas são investimentos; as deles são desperdício.' }, dimension: 'H' }, { text: { es: 'Si juzgo el gasto de otros, tengo que aplicar los mismos criterios al mío.', en: 'If I judge others\' spending, I have to apply the same criteria to mine.', fr: 'Si je juge les dépenses des autres, je dois appliquer les mêmes critères aux miennes.', de: 'Wenn ich die Ausgaben anderer beurteile, muss ich dieselben Kriterien auf meine eigenen anwenden.', it: 'Se giudico le spese degli altri, devo applicare gli stessi criteri alle mie.', pt: 'Se julgo os gastos dos outros, tenho que aplicar os mesmos critérios aos meus.' }, dimension: 'C' }, { text: { es: 'Reconozco que tengo estándares dobles en este tema.', en: 'I recognize I have double standards on this.', fr: 'Je reconnais que j\'ai deux poids deux mesures sur ce sujet.', de: 'Ich erkenne, dass ich in diesem Bereich doppelte Standards habe.', it: 'Riconosco di avere un doppio standard su questo tema.', pt: 'Reconheço que tenho dois pesos e duas medidas nesse assunto.' }, dimension: 'A' }, { text: { es: 'No todo gasto es igual. El contexto y la prioridad importan.', en: 'Not all spending is the same. Context and priority matter.', fr: 'Toutes les dépenses ne sont pas égales. Le contexte et la priorité comptent.', de: 'Nicht alle Ausgaben sind gleich. Kontext und Priorität sind wichtig.', it: 'Non tutta la spesa è uguale. Il contesto e la priorità contano.', pt: 'Nem todo gasto é igual. O contexto e a prioridade importam.' }, dimension: 'F' }] },
        { id: 6, situation: { es: 'Dices que valoras la privacidad pero hablas de la vida privada de otros regularmente.', en: 'You say you value privacy but regularly talk about others\' private lives.', fr: 'Tu dis que tu valorises la vie privée mais tu parles régulièrement de la vie privée des autres.', de: 'Du sagst, du schätzt Privatsphäre, redest aber regelmäßig über das Privatleben anderer.', it: 'Dici di valorizzare la privacy ma parli regolarmente della vita privata degli altri.', pt: 'Você diz valorizar a privacidade mas fala regularmente sobre a vida privada dos outros.' }, options: [{ text: { es: 'Yo hablo de hechos, no de rumores. Es diferente.', en: 'I talk about facts, not rumors. It\'s different.', fr: 'Je parle de faits, pas de rumeurs. C\'est différent.', de: 'Ich rede über Fakten, nicht über Gerüchte. Das ist anders.', it: 'Parlo di fatti, non di voci. È diverso.', pt: 'Eu falo de fatos, não de rumores. É diferente.' }, dimension: 'H' }, { text: { es: 'Si valoro la privacidad, no debería hablar de la vida de otros sin su permiso.', en: 'If I value privacy, I shouldn\'t talk about others\' lives without their permission.', fr: 'Si je valorise la vie privée, je ne devrais pas parler de la vie des autres sans leur permission.', de: 'Wenn ich Privatsphäre schätze, sollte ich nicht ohne Erlaubnis über das Leben anderer reden.', it: 'Se valuto la privacy, non dovrei parlare della vita degli altri senza il loro permesso.', pt: 'Se valorizo a privacidade, não devo falar sobre a vida dos outros sem sua permissão.' }, dimension: 'C' }, { text: { es: 'Sí, hay inconsistencia. No es mi mejor rasgo.', en: 'Yes, there\'s inconsistency. It\'s not my best trait.', fr: 'Oui, il y a une incohérence. Ce n\'est pas mon meilleur trait.', de: 'Ja, es gibt eine Inkonsistenz. Es ist nicht meine beste Eigenschaft.', it: 'Sì, c\'è incoerenza. Non è il mio tratto migliore.', pt: 'Sim, há inconsistência. Não é minha melhor característica.' }, dimension: 'A' }, { text: { es: 'Compartir información no siempre viola la privacidad. Depende del contexto.', en: 'Sharing information doesn\'t always violate privacy. It depends on context.', fr: 'Partager des informations ne viole pas toujours la vie privée. Ça dépend du contexte.', de: 'Das Teilen von Informationen verletzt nicht immer die Privatsphäre. Es hängt vom Kontext ab.', it: 'Condividere informazioni non viola sempre la privacy. Dipende dal contesto.', pt: 'Compartilhar informações nem sempre viola a privacidade. Depende do contexto.' }, dimension: 'F' }] },
        { id: 7, situation: { es: 'Predicas el trabajo duro pero usas atajos cuando nadie mira.', en: 'You preach hard work but take shortcuts when no one is watching.', fr: 'Tu prêches le travail acharné mais tu prends des raccourcis quand personne ne regarde.', de: 'Du predigst harte Arbeit, nimmst aber Abkürzungen, wenn niemand zuschaut.', it: 'Predichi il lavoro duro ma prendi scorciatoie quando nessuno guarda.', pt: 'Você prega o trabalho duro mas usa atalhos quando ninguém está vendo.' }, options: [{ text: { es: 'Los atajos eficientes no son lo mismo que la pereza.', en: 'Efficient shortcuts aren\'t the same as laziness.', fr: 'Les raccourcis efficaces ne sont pas la même chose que la paresse.', de: 'Effiziente Abkürzungen sind nicht dasselbe wie Faulheit.', it: 'Le scorciatoie efficienti non sono la stessa cosa della pigrizia.', pt: 'Atalhos eficientes não são o mesmo que preguiça.' }, dimension: 'H' }, { text: { es: 'Si predico algo, necesito estar dispuesto/a a hacerlo yo también.', en: 'If I preach something, I need to be willing to do it myself too.', fr: 'Si je prêche quelque chose, je dois être prêt(e) à le faire moi-même aussi.', de: 'Wenn ich etwas predige, muss ich bereit sein, es selbst zu tun.', it: 'Se predico qualcosa, devo essere disposto/a a farlo anche io.', pt: 'Se prego algo, preciso estar disposto/a a fazê-lo também.' }, dimension: 'C' }, { text: { es: 'No voy a mentir: no siempre practico lo que predico.', en: 'I\'m not going to lie: I don\'t always practice what I preach.', fr: 'Je ne vais pas mentir : je ne pratique pas toujours ce que je prêche.', de: 'Ich werde nicht lügen: Ich praktiziere nicht immer, was ich predige.', it: 'Non lo negherò: non pratico sempre quello che predico.', pt: 'Não vou mentir: não pratico sempre o que prego.' }, dimension: 'A' }, { text: { es: 'La adaptabilidad y los atajos inteligentes no contradicen el trabajo duro.', en: 'Adaptability and smart shortcuts don\'t contradict hard work.', fr: 'L\'adaptabilité et les raccourcis intelligents ne contredisent pas le travail acharné.', de: 'Anpassungsfähigkeit und intelligente Abkürzungen widersprechen der harten Arbeit nicht.', it: 'L\'adattabilità e le scorciatoie intelligenti non contraddicono il lavoro duro.', pt: 'Adaptabilidade e atalhos inteligentes não contradizem o trabalho duro.' }, dimension: 'F' }] },
        { id: 8, situation: { es: 'Criticas el consumismo mientras compras artículos de marca regularmente.', en: 'You criticize consumerism while regularly buying branded items.', fr: 'Tu critiques le consumérisme tout en achetant régulièrement des articles de marque.', de: 'Du kritisierst Konsumismus, kaufst aber regelmäßig Markenartikel.', it: 'Critichi il consumismo mentre acquisti regolarmente articoli di marca.', pt: 'Você critica o consumismo enquanto compra artigos de marca regularmente.' }, options: [{ text: { es: 'Hay marcas que valen y que no son consumismo vacío.', en: 'There are brands that have value and aren\'t empty consumerism.', fr: 'Il y a des marques qui valent quelque chose et qui ne sont pas du consumérisme vide.', de: 'Es gibt Marken, die ihren Wert haben und kein leerer Konsumismus sind.', it: 'Ci sono marchi che valgono e che non sono consumismo vuoto.', pt: 'Há marcas que valem e que não são consumismo vazio.' }, dimension: 'H' }, { text: { es: 'Si critico el consumismo, tengo que revisar mis propios patrones de compra.', en: 'If I criticize consumerism, I have to review my own buying patterns.', fr: 'Si je critique le consumérisme, je dois revoir mes propres habitudes d\'achat.', de: 'Wenn ich Konsumismus kritisiere, muss ich meine eigenen Kaufmuster überprüfen.', it: 'Se critico il consumismo, devo rivedere i miei stessi schemi di acquisto.', pt: 'Se critico o consumismo, tenho que revisar meus próprios padrões de compra.' }, dimension: 'C' }, { text: { es: 'Es una de mis contradicciones más obvias. Lo acepto.', en: 'It\'s one of my most obvious contradictions. I accept it.', fr: 'C\'est l\'une de mes contradictions les plus évidentes. Je l\'accepte.', de: 'Es ist eine meiner offensichtlichsten Widersprüche. Ich akzeptiere es.', it: 'È una delle mie contraddizioni più evidenti. La accetto.', pt: 'É uma das minhas contradições mais óbvias. Aceito isso.' }, dimension: 'A' }, { text: { es: 'No todo consumo es consumismo. Se puede ser crítico y también comprar.', en: 'Not all consumption is consumerism. You can be critical and still buy things.', fr: 'Tout consumo n\'est pas du consumérisme. On peut être critique et aussi acheter.', de: 'Nicht jeder Konsum ist Konsumismus. Man kann kritisch sein und trotzdem kaufen.', it: 'Non tutto il consumo è consumismo. Si può essere critici e anche comprare.', pt: 'Nem todo consumo é consumismo. Pode-se ser crítico e também comprar.' }, dimension: 'F' }] },
        { id: 9, situation: { es: 'Dices que no te importa lo que piensen los demás pero cambias tu comportamiento según el contexto social.', en: 'You say you don\'t care what others think but change your behavior based on social context.', fr: 'Tu dis que tu ne te soucies pas de ce que les autres pensent mais tu changes ton comportement selon le contexte social.', de: 'Du sagst, es ist dir egal, was andere denken, änderst aber dein Verhalten je nach sozialem Kontext.', it: 'Dici che non ti importa cosa pensano gli altri ma cambi il tuo comportamento in base al contesto sociale.', pt: 'Você diz que não se importa com o que os outros pensam mas muda seu comportamento conforme o contexto social.' }, options: [{ text: { es: 'Eso es solo inteligencia social, no hipocresía.', en: 'That\'s just social intelligence, not hypocrisy.', fr: 'C\'est juste de l\'intelligence sociale, pas de l\'hypocrisie.', de: 'Das ist nur soziale Intelligenz, keine Heuchelei.', it: 'È solo intelligenza sociale, non ipocrisia.', pt: 'Isso é apenas inteligência social, não hipocrisia.' }, dimension: 'H' }, { text: { es: 'Si realmente no me importara, actuaría igual en todos los contextos.', en: 'If I truly didn\'t care, I would act the same in all contexts.', fr: 'Si ça ne m\'importait vraiment pas, j\'agirais de la même façon dans tous les contextes.', de: 'Wenn es mir wirklich egal wäre, würde ich in allen Kontexten gleich handeln.', it: 'Se davvero non me ne importasse, agirei allo stesso modo in tutti i contesti.', pt: 'Se realmente não me importasse, agiria da mesma forma em todos os contextos.' }, dimension: 'C' }, { text: { es: 'Sí, la verdad es que sí me importa lo que piensan. Me autoengaño a veces.', en: 'Yes, the truth is I do care what they think. I self-deceive sometimes.', fr: 'Oui, la vérité c\'est que ça m\'importe ce qu\'ils pensent. Je me trompe parfois moi-même.', de: 'Ja, die Wahrheit ist, dass mir doch wichtig ist, was sie denken. Manchmal täusche ich mich selbst.', it: 'Sì, la verità è che mi importa cosa pensano. A volte mi autoinganni.', pt: 'Sim, a verdade é que me importa sim o que pensam. Às vezes me enganô a mim mesmo/a.' }, dimension: 'A' }, { text: { es: 'Adaptar el comportamiento al contexto es madurez, no incoherencia.', en: 'Adapting behavior to context is maturity, not inconsistency.', fr: 'Adapter son comportement au contexte, c\'est de la maturité, pas de l\'incohérence.', de: 'Das Verhalten an den Kontext anzupassen ist Reife, keine Inkonsistenz.', it: 'Adattare il comportamento al contesto è maturità, non incoerenza.', pt: 'Adaptar o comportamento ao contexto é maturidade, não incoerência.' }, dimension: 'F' }] },
        { id: 10, situation: { es: '¿Cómo describirías tu relación entre lo que dices y lo que haces?', en: 'How would you describe the relationship between what you say and what you do?', fr: 'Comment décrirais-tu la relation entre ce que tu dis et ce que tu fais ?', de: 'Wie würdest du die Beziehung zwischen dem, was du sagst, und dem, was du tust, beschreiben?', it: 'Come descriveresti il rapporto tra quello che dici e quello che fai?', pt: 'Como você descreveria a relação entre o que você diz e o que você faz?' }, options: [{ text: { es: 'Generalmente consistente, con excepciones justificadas.', en: 'Generally consistent, with justified exceptions.', fr: 'Généralement cohérent(e), avec des exceptions justifiées.', de: 'Im Allgemeinen konsistent, mit gerechtfertigten Ausnahmen.', it: 'Generalmente coerente, con eccezioni giustificate.', pt: 'Geralmente consistente, com exceções justificadas.' }, dimension: 'H' }, { text: { es: 'Aspiro a la coherencia y cuando fallo, me lo tomo en serio.', en: 'I aspire to coherence and when I fail, I take it seriously.', fr: 'J\'aspire à la cohérence et quand j\'échoue, je le prends au sérieux.', de: 'Ich strebe nach Kohärenz und wenn ich scheitere, nehme ich es ernst.', it: 'Aspiro alla coerenza e quando fallisco, lo prendo sul serio.', pt: 'Aspiro à coerência e quando falho, levo a sério.' }, dimension: 'C' }, { text: { es: 'Hay brechas. Las veo y trabajo en ellas.', en: 'There are gaps. I see them and work on them.', fr: 'Il y a des écarts. Je les vois et j\'y travaille.', de: 'Es gibt Lücken. Ich sehe sie und arbeite daran.', it: 'Ci sono divari. Li vedo e ci lavoro su.', pt: 'Há lacunas. As vejo e trabalho nelas.' }, dimension: 'A' }, { text: { es: 'Ningún ser humano es perfectamente consistente. Lo importante es la dirección.', en: 'No human being is perfectly consistent. What matters is the direction.', fr: 'Aucun être humain n\'est parfaitement cohérent. Ce qui compte, c\'est la direction.', de: 'Kein Mensch ist vollkommen konsistent. Was zählt, ist die Richtung.', it: 'Nessun essere umano è perfettamente coerente. Ciò che conta è la direzione.', pt: 'Nenhum ser humano é perfeitamente consistente. O que importa é a direção.' }, dimension: 'F' }] },
      ],
      characters: [
        { name: { es: 'El Hipócrita Clásico', en: 'The Classic Hypocrite', fr: 'L\'Hypocrite Classique', de: 'Der Klassische Heuchler', it: 'L\'Ipocrita Classico', pt: 'O Hipócrita Clássico' }, dimensions: ['H'], photo: '/characters/hypocrite.jpg', description: { es: 'Tiene una norma para él y otra para los demás.', en: 'Has one standard for themselves and another for everyone else.', fr: 'A une norme pour lui-même et une autre pour les autres.', de: 'Hat einen Standard für sich selbst und einen anderen für alle anderen.', it: 'Ha uno standard per sé e un altro per gli altri.', pt: 'Tem um padrão para si mesmo e outro para os demais.' }, philosophy: { es: 'No eres consciente de tu doble estándar — o lo justificas tan bien que se convierte en verdad para ti. Cada excepción para ti misma/o tiene una razón. Las reglas generales son para los demás.', en: 'You\'re not aware of your double standard — or you justify it so well it becomes truth for you. Every exception for yourself has a reason. General rules are for others.', fr: 'Tu n\'es pas conscient(e) de ton double standard — ou tu le justifies si bien qu\'il devient vérité pour toi. Chaque exception pour toi-même a une raison. Les règles générales sont pour les autres.', de: 'Du bist dir deines doppelten Standards nicht bewusst — oder du rechtfertigst ihn so gut, dass er für dich zur Wahrheit wird. Jede Ausnahme für dich selbst hat einen Grund. Allgemeine Regeln gelten für andere.', it: 'Non sei consapevole del tuo doppio standard — o lo giustifichi così bene che diventa verità per te. Ogni eccezione per te stesso/a ha una ragione. Le regole generali sono per gli altri.', pt: 'Você não está ciente do seu duplo padrão — ou o justifica tão bem que se torna verdade para você. Cada exceção para si mesmo tem uma razão. As regras gerais são para os outros.' } },
        { name: { es: 'El Coherente', en: 'The Coherent One', fr: 'Le Cohérent', de: 'Der Kohärente', it: 'Il Coerente', pt: 'O Coerente' }, dimensions: ['C'], photo: '/characters/coherent.jpg', description: { es: 'Vive lo que predica. No siempre fácil, pero siempre intencional.', en: 'Lives what they preach. Not always easy, but always intentional.', fr: 'Vit ce qu\'il prêche. Pas toujours facile, mais toujours intentionnel.', de: 'Lebt, was er predigt. Nicht immer einfach, aber immer absichtlich.', it: 'Vive quello che predica. Non sempre facile, ma sempre intenzionale.', pt: 'Vive o que prega. Nem sempre fácil, mas sempre intencional.' }, philosophy: { es: 'Para ti, la integridad es práctica diaria, no solo discurso. Cuando ves una brecha entre lo que dices y lo que haces, actúas. Eso requiere un nivel de honestidad consigo mismo/a que no es común.', en: 'For you, integrity is daily practice, not just talk. When you see a gap between what you say and what you do, you act. That requires a level of self-honesty that isn\'t common.', fr: 'Pour toi, l\'intégrité est une pratique quotidienne, pas seulement un discours. Quand tu vois un écart entre ce que tu dis et ce que tu fais, tu agis. Cela demande un niveau d\'honnêteté envers soi-même qui n\'est pas courant.', de: 'Für dich ist Integrität tägliche Praxis, nicht nur Gerede. Wenn du eine Lücke zwischen dem, was du sagst, und dem, was du tust, siehst, handelst du. Das erfordert ein Maß an Selbstehrlichkeit, das nicht üblich ist.', it: 'Per te, l\'integrità è pratica quotidiana, non solo discorso. Quando vedi un divario tra quello che dici e quello che fai, agisci. Questo richiede un livello di onestà verso se stessi che non è comune.', pt: 'Para você, a integridade é prática diária, não apenas discurso. Quando vê uma lacuna entre o que diz e o que faz, age. Isso requer um nível de honestidade consigo mesmo que não é comum.' } },
        { name: { es: 'El Consciente de sus Contradicciones', en: 'The Contradiction-Aware', fr: 'Le Conscient de ses Contradictions', de: 'Der Widerspruchsbewusste', it: 'Il Consapevole delle Contraddizioni', pt: 'O Consciente das Contradições' }, dimensions: ['A'], photo: '/characters/contradiction-aware.jpg', description: { es: 'Sabe que tiene incoherencias y no pretende lo contrario.', en: 'Knows they have inconsistencies and doesn\'t pretend otherwise.', fr: 'Sait qu\'il a des incohérences et ne prétend pas le contraire.', de: 'Weiß, dass er Inkonsistenzen hat, und tut nicht so als ob nicht.', it: 'Sa di avere incoerenze e non finge il contrario.', pt: 'Sabe que tem incoerências e não finge o contrário.' }, philosophy: { es: 'Tu honestidad sobre tus propias contradicciones es en sí misma una forma de integridad. No pretendes ser perfecto/a — simplemente eres transparente sobre dónde estás. Eso ya es mucho.', en: 'Your honesty about your own contradictions is itself a form of integrity. You don\'t pretend to be perfect — you\'re simply transparent about where you are. That\'s already a lot.', fr: 'Ton honnêteté sur tes propres contradictions est en soi une forme d\'intégrité. Tu ne prétends pas être parfait(e) — tu es simplement transparent(e) sur où tu en es. C\'est déjà beaucoup.', de: 'Deine Ehrlichkeit über deine eigenen Widersprüche ist selbst eine Form von Integrität. Du tust nicht so, als wärst du perfekt — du bist einfach transparent darüber, wo du stehst. Das ist schon viel.', it: 'La tua onestà sulle tue stesse contraddizioni è in sé una forma di integrità. Non fingi di essere perfetto/a — sei semplicemente trasparente su dove ti trovi. Questo è già molto.', pt: 'Sua honestidade sobre suas próprias contradições é em si mesma uma forma de integridade. Você não finge ser perfeito/a — simplesmente é transparente sobre onde está. Isso já é muito.' } },
        { name: { es: 'El Contextual Flexible', en: 'The Flexible Contextualist', fr: 'Le Contextuel Flexible', de: 'Der Flexible Kontextualist', it: 'Il Contestuale Flessibile', pt: 'O Contextual Flexível' }, dimensions: ['F'], photo: '/characters/contextual.jpg', description: { es: 'Las reglas no son absolutas. Todo depende del contexto.', en: 'Rules aren\'t absolute. Everything depends on context.', fr: 'Les règles ne sont pas absolues. Tout dépend du contexte.', de: 'Regeln sind nicht absolut. Alles hängt vom Kontext ab.', it: 'Le regole non sono assolute. Tutto dipende dal contesto.', pt: 'As regras não são absolutas. Tudo depende do contexto.' }, philosophy: { es: 'Para ti, la consistencia perfecta es una fantasía. El mundo es complejo, los contextos importan y la flexibilidad no es hipocresía — es madurez. El peligro es cuando la flexibilidad se convierte en excusa.', en: 'For you, perfect consistency is a fantasy. The world is complex, contexts matter and flexibility isn\'t hypocrisy — it\'s maturity. The danger is when flexibility becomes an excuse.', fr: 'Pour toi, la cohérence parfaite est une fantaisie. Le monde est complexe, les contextes comptent et la flexibilité n\'est pas de l\'hypocrisie — c\'est de la maturité. Le danger, c\'est quand la flexibilité devient une excuse.', de: 'Für dich ist vollkommene Konsistenz eine Fantasie. Die Welt ist komplex, Kontexte sind wichtig und Flexibilität ist keine Heuchelei — es ist Reife. Die Gefahr besteht, wenn Flexibilität zur Ausrede wird.', it: 'Per te, la coerenza perfetta è una fantasia. Il mondo è complesso, i contesti contano e la flessibilità non è ipocrisia — è maturità. Il pericolo è quando la flessibilità diventa una scusa.', pt: 'Para você, a consistência perfeita é uma fantasia. O mundo é complexo, os contextos importam e a flexibilidade não é hipocrisia — é maturidade. O perigo é quando a flexibilidade vira desculpa.' } },
        { name: { es: 'El Autoengañado Elegante', en: 'The Elegant Self-Deceiver', fr: 'Le Trompeur Élégant de Lui-Même', de: 'Der Elegante Selbstbetrüger', it: 'L\'Autoingannato Elegante', pt: 'O Autoiludido Elegante' }, dimensions: ['H', 'F'], photo: '/characters/self-deceived.jpg', description: { es: 'Tiene respuesta para todo. Sus excepciones siempre tienen justificación.', en: 'Has an answer for everything. Their exceptions always have justification.', fr: 'A une réponse à tout. Ses exceptions ont toujours une justification.', de: 'Hat eine Antwort auf alles. Seine Ausnahmen haben immer eine Begründung.', it: 'Ha una risposta per tutto. Le sue eccezioni hanno sempre una giustificazione.', pt: 'Tem resposta para tudo. Suas exceções sempre têm justificativa.' }, philosophy: { es: 'Eres el tipo más sofisticado de hipócrita: el que tiene una narrativa coherente para cada inconsistencia. No mientes — simplemente construyes marcos que hacen que tus excepciones siempre parezcan razonables.', en: 'You\'re the most sophisticated type of hypocrite: the one with a coherent narrative for every inconsistency. You don\'t lie — you simply build frameworks that make your exceptions always seem reasonable.', fr: 'Tu es le type d\'hypocrite le plus sophistiqué : celui qui a un récit cohérent pour chaque inconsistance. Tu ne mens pas — tu construis simplement des cadres qui font que tes exceptions semblent toujours raisonnables.', de: 'Du bist der ausgefeilteste Typ von Heuchler: derjenige, der für jede Inkonsistenz eine kohärente Erzählung hat. Du lügst nicht — du baust einfach Rahmen, die deine Ausnahmen immer vernünftig erscheinen lassen.', it: 'Sei il tipo più sofisticato di ipocrita: quello che ha una narrativa coerente per ogni incoerenza. Non menti — semplicemente costruisci quadri che fanno sì che le tue eccezioni sembrino sempre ragionevoli.', pt: 'Você é o tipo mais sofisticado de hipócrita: aquele que tem uma narrativa coerente para cada inconsistência. Não mente — simplesmente constrói frameworks que fazem suas exceções sempre parecerem razoáveis.' } },
        { name: { es: 'El En Proceso', en: 'The Work in Progress', fr: 'Le En Cours de Processus', de: 'Der im Prozess Befindliche', it: 'Il In Elaborazione', pt: 'O Em Processo' }, dimensions: ['H', 'A'], photo: '/characters/in-process.jpg', description: { es: 'Ve sus hipocresías y trabaja en ellas, aunque despacio.', en: 'Sees their hypocrisies and works on them, albeit slowly.', fr: 'Voit ses hypocrisies et y travaille, même si c\'est lentement.', de: 'Sieht seine Heucheleien und arbeitet daran, wenn auch langsam.', it: 'Vede le sue ipocrisie e ci lavora su, anche se lentamente.', pt: 'Vê suas hipocrisias e trabalha nelas, embora lentamente.' }, philosophy: { es: 'La autoconciencia es el primer paso. Lo ves, lo nombras y a veces todavía caes en ello. Pero hay movimiento. La diferencia entre el hipócrita estático y el que crece es exactamente ese reconocimiento.', en: 'Self-awareness is the first step. You see it, you name it and sometimes you still fall into it. But there\'s movement. The difference between the static hypocrite and the growing one is exactly that recognition.', fr: 'La conscience de soi est la première étape. Tu le vois, tu le nommes et parfois tu y tombes encore. Mais il y a un mouvement. La différence entre l\'hypocrite statique et celui qui grandit, c\'est exactement cette reconnaissance.', de: 'Selbstbewusstsein ist der erste Schritt. Du siehst es, du nennst es und manchmal fällst du noch darauf herein. Aber es gibt Bewegung. Der Unterschied zwischen dem statischen Heuchler und dem, der wächst, ist genau diese Anerkennung.', it: 'La consapevolezza di sé è il primo passo. Lo vedi, lo nomini e a volte ci ricaschi ancora. Ma c\'è movimento. La differenza tra l\'ipocrita statico e quello che cresce è esattamente quel riconoscimento.', pt: 'A autoconsciência é o primeiro passo. Você vê, nomeia e às vezes ainda cai nisso. Mas há movimento. A diferença entre o hipócrita estático e o que cresce é exatamente esse reconhecimento.' } },
        { name: { es: 'El Realista Honesto', en: 'The Honest Realist', fr: 'Le Réaliste Honnête', de: 'Der Ehrliche Realist', it: 'Il Realista Onesto', pt: 'O Realista Honesto' }, dimensions: ['A', 'F'], photo: '/characters/realistic-honest.jpg', description: { es: 'Sabe que es imperfecto y no juzga a los demás por el mismo motivo.', en: 'Knows they\'re imperfect and doesn\'t judge others for the same reason.', fr: 'Sait qu\'il est imparfait et ne juge pas les autres pour la même raison.', de: 'Weiß, dass er unvollkommen ist, und urteilt aus demselben Grund nicht über andere.', it: 'Sa di essere imperfetto e non giudica gli altri per lo stesso motivo.', pt: 'Sabe que é imperfeito e não julga os outros pelo mesmo motivo.' }, philosophy: { es: 'Reconoces tus brechas y por eso también eres compasivo/a con las de los demás. No eres duro/a con tu hipocresía ni con la ajena — simplemente la reconoces como parte de la condición humana.', en: 'You recognize your gaps and so you\'re also compassionate with those of others. You\'re not harsh with your own hypocrisy or others\' — you simply recognize it as part of the human condition.', fr: 'Tu reconnais tes lacunes et c\'est pourquoi tu es aussi compatissant(e) avec celles des autres. Tu n\'es pas dur(e) avec ton hypocrisie ni avec celle des autres — tu la reconnais simplement comme faisant partie de la condition humaine.', de: 'Du erkennst deine Lücken und bist deshalb auch mitfühlend gegenüber denen anderer. Du bist nicht hart zu deiner eigenen Heuchelei oder der anderer — du erkennst sie einfach als Teil der menschlichen Natur.', it: 'Riconosci i tuoi divari e per questo sei anche compassionevole con quelli degli altri. Non sei duro/a con la tua ipocrisia né con quella altrui — la riconosci semplicemente come parte della condizione umana.', pt: 'Você reconhece suas lacunas e por isso também é compassivo/a com as dos outros. Não é duro/a com sua hipocrisia nem com a alheia — simplesmente a reconhece como parte da condição humana.' } },
        { name: { es: 'El Íntegro en Movimiento', en: 'Integrity in Motion', fr: 'L\'Intègre en Mouvement', de: 'Die Integrität in Bewegung', it: 'L\'Integro in Movimento', pt: 'A Integridade em Movimento' }, dimensions: ['C', 'A'], photo: '/characters/integrity.jpg', description: { es: 'Aspira a la coherencia y cuando falla, lo reconoce y ajusta.', en: 'Aspires to coherence and when they fail, recognizes it and adjusts.', fr: 'Aspire à la cohérence et quand il échoue, il le reconnaît et s\'ajuste.', de: 'Strebt nach Kohärenz und erkennt und passt an, wenn er scheitert.', it: 'Aspira alla coerenza e quando fallisce, lo riconosce e si adegua.', pt: 'Aspira à coerência e quando falha, reconhece e ajusta.' }, philosophy: { es: 'Combinas la aspiración a la coherencia con la honestidad sobre los momentos en que no llegas. Eso crea una integridad dinámica: no perfecta, pero genuina. Es el tipo más sostenible de honestidad.', en: 'You combine the aspiration to coherence with honesty about the moments when you fall short. That creates a dynamic integrity: not perfect, but genuine. It\'s the most sustainable kind of honesty.', fr: 'Tu combines l\'aspiration à la cohérence avec l\'honnêteté sur les moments où tu n\'y arrives pas. Cela crée une intégrité dynamique : pas parfaite, mais authentique. C\'est le type d\'honnêteté le plus durable.', de: 'Du kombinierst das Streben nach Kohärenz mit Ehrlichkeit über die Momente, in denen du nicht erreichst. Das schafft eine dynamische Integrität: nicht perfekt, aber echt. Das ist die nachhaltigste Art von Ehrlichkeit.', it: 'Combini l\'aspirazione alla coerenza con l\'onestà sui momenti in cui non ci riesci. Questo crea un\'integrità dinamica: non perfetta, ma genuina. È il tipo più sostenibile di onestà.', pt: 'Você combina a aspiração à coerência com a honestidade sobre os momentos em que não alcança. Isso cria uma integridade dinâmica: não perfeita, mas genuína. É o tipo mais sustentável de honestidade.' } },
      ],
    },
  });
}
